incomplete = {'case_id': 'CASO-CUS-042-1A', 'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
# skeptic_check: form+pass contract

